    ov.style.display = 'block';
    ov.style.left = (r1.left - wr.left) + 'px';
    ov.style.top = (r1.top - wr.top) + 'px';
    ov.style.width = (r2.right - r1.left) + 'px';
    ov.style.height = (r2.bottom - r1.top) + 'px';
